export const articles = sqliteTable(
  'articles',
  {
    id: integer('id').primaryKey(),
    title: text('title'),
    heroImage: integer('hero_image_id').references(() => media.id, {
      onDelete: 'set null',
    }),
    content: text('content', { mode: 'json' }),
    meta_title: text('meta_title'),
    meta_image: integer('meta_image_id').references(() => media.id, {
      onDelete: 'set null',
    }),
    meta_description: text('meta_description'),
    publishedAt: text('published_at').default(sql`(strftime('%Y-%m-%dT%H:%M:%fZ', 'now'))`),
    createdBy: integer('created_by_id').references(() => users.id, {
      onDelete: 'set null',
    }),
    generateSlug: integer('generate_slug', { mode: 'boolean' }).default(true),
    slug: text('slug'),
    updatedAt: text('updated_at')
      .notNull()
      .default(sql`(strftime('%Y-%m-%dT%H:%M:%fZ', 'now'))`),
    createdAt: text('created_at')
      .notNull()
      .default(sql`(strftime('%Y-%m-%dT%H:%M:%fZ', 'now'))`),
    _status: text('_status', { enum: ['draft', 'published'] }).default('draft'),
  },
  (columns) => [
    index('articles_hero_image_idx').on(columns.heroImage),
    index('articles_meta_meta_image_idx').on(columns.meta_image),
    index('articles_created_by_idx').on(columns.createdBy),
    uniqueIndex('articles_slug_idx').on(columns.slug),
    index('articles_updated_at_idx').on(columns.updatedAt),
    index('articles_created_at_idx').on(columns.createdAt),
    index('articles__status_idx').on(columns._status),
  ],
)

